// Garantir envelope do trigger
let _triggerEnvelope = {};
try { _triggerEnvelope = $('TRG_FromOrchestrator').item.json.envelope || {}; } catch(e) {}

// TRF_HardValidate - Hard rules validation with CONTEXTUAL CHECK
const input = $json;

// Handle both formats: with envelope or direct response_text
const envelope = input.envelope || {};
const agentResponse = input.agent_response || {};

// === GET USER MESSAGE FOR CONTEXT ===
const userMessage = envelope.user_message || envelope.text_raw || '';

// === EXTRACT TEXT ===
let draftText = '';

// 1. Check direct response_text
if (input.response_text) {
  draftText = input.response_text;
}

// 2. Check summary (from Capture workflow)
if (!draftText && input.summary) {
  draftText = input.summary;
}

// 3. Check agent_response.text
if (!draftText) {
  const textField = agentResponse.text;
  if (typeof textField === 'string') {
    draftText = textField;
  } else if (textField && typeof textField === 'object') {
    draftText = textField.response_text || textField.text || textField.message || textField.content || '';
  }
}

// 4. Check agent_response.output (langchain format)
if (!draftText && agentResponse.output) {
  if (typeof agentResponse.output === 'string') {
    draftText = agentResponse.output;
  } else if (agentResponse.output.response_text) {
    draftText = agentResponse.output.response_text;
  }
}

// If no text found, skip validation
if (!draftText) {
  return [{
    json: {
      passed: true,
      reason: 'no_text_to_validate',
      draft_text: '',
      user_message: userMessage,
      envelope: (_triggerEnvelope.from_phone ? _triggerEnvelope : envelope),
      agent_response: agentResponse,
      validation_flags: input.validation_flags || {}
    }
  }];
}

// === HARD RULES ===
const rules = [];

if (!draftText.trim()) {
  rules.push({ rule: 'empty_response', passed: false });
}

if (draftText.trim().length < 5) {
  rules.push({ rule: 'too_short', passed: false });
}

const errorPatterns = ['erro', 'error', 'falha', 'failed', 'undefined', 'null'];
const hasError = errorPatterns.some(p => draftText.toLowerCase().includes(p) && draftText.length < 50);
if (hasError) {
  rules.push({ rule: 'contains_error', passed: false });
}

// Check for non-contextual response (greeting when user asked for action)
const actionKeywords = ['lembra', 'anota', 'salva', 'cria', 'agenda', 'marca', 'preciso', 'tenho que'];
const isActionRequest = actionKeywords.some(k => userMessage.toLowerCase().includes(k));
const greetingPatterns = ['bom dia', 'boa tarde', 'boa noite', 'olá', 'oi ', 'como posso ajudar'];
const isGenericGreeting = greetingPatterns.some(p => draftText.toLowerCase().includes(p)) && draftText.length < 100;

if (isActionRequest && isGenericGreeting) {
  rules.push({ rule: 'generic_greeting_for_action', passed: false });
}

// CONTEXTUAL COHERENCE CHECK: Detect when response is a list of items
// but user asked a personal/social question
const personalPatterns = [
  /qual\s+(meu|seu|é\s+meu|é\s+o\s+meu)\s+nome/i,
  /meu\s+nome.*qual/i,
  /quem\s+sou\s+eu/i,
  /como\s+(me\s+)?chamo/i,
  /qual\s+sua\s+fun/i,
  /o\s+que\s+voc/i,
  /quem\s+é\s+voc/i,
  /qual\s+minha\s+empresa/i
];
const isPersonalQuestion = personalPatterns.some(p => p.test(userMessage));
const looksLikeItemList = /\d{2}\/\d{2}\/\d{4}/.test(draftText) || 
  (draftText.includes('🔔') && draftText.includes('🕐')) ||
  (draftText.includes('Pendente') && draftText.includes('Conclu'));
if (isPersonalQuestion && looksLikeItemList) {
  rules.push({ rule: 'item_list_for_personal_question', passed: false });
}

// NEW: Check for internal instruction leakage (calendar/tasks metadata)
const internalLeakPatterns = ['calendar_action', 'tasks_action', 'hints', 'time_window', 'needs_clarification', '"action":', '"route":', 'provider:', 'gtasks', 'gcal'];
const hasInternalLeak = internalLeakPatterns.some(p => draftText.toLowerCase().includes(p.toLowerCase()));
if (hasInternalLeak) {
  rules.push({ rule: 'internal_instruction_leak', passed: false });
}


// NEW: Check for phone number leakage in response
const phonePattern = /\+?\d{2}\s?\d{2}\s?\d{4,5}[\s-]?\d{4}/;
const hasPhoneLeak = phonePattern.test(draftText);
if (hasPhoneLeak) {
  rules.push({ rule: 'phone_number_leak', passed: false });
}

// NEW: Check for "mensagem de" or "chegou do número" patterns (treating user msg as third-party)
const thirdPartyPatterns = ['chegou do número', 'mensagem de', 'recebeu uma mensagem', 'do número +'];
const hasThirdPartyLeak = thirdPartyPatterns.some(p => draftText.toLowerCase().includes(p.toLowerCase()));
if (hasThirdPartyLeak) {
  rules.push({ rule: 'third_party_message_leak', passed: false });
}

const failedRules = rules.filter(r => !r.passed);
const allPassed = failedRules.length === 0;

// Build validation flags
const validationFlags = {};
failedRules.forEach(r => { validationFlags[r.rule] = true; });

return [{
  json: {
    passed: allPassed,
    force_regenerate: !allPassed,
    reason: allPassed ? 'all_rules_passed' : failedRules.map(r => r.rule).join(','),
    draft_text: draftText,
    user_message: userMessage,
    envelope: (_triggerEnvelope.from_phone ? _triggerEnvelope : envelope),
    agent_response: agentResponse,
    validation_flags: validationFlags
  }
}];

// Garantir envelope do trigger
let _triggerEnvelope = {};
try { _triggerEnvelope = $('TRG_FromOrchestrator').item.json.envelope || {}; } catch(e) {}
const _envelope = (_triggerEnvelope.from_phone ? _triggerEnvelope : ($json.envelope || {}));

// TRF_UseFallback - Use SAFE fallback when QC rejects the response
const data = $('TRF_HardValidate').item.json;
const validationFlags = data.validation_flags || {};
const failedRules = Object.keys(validationFlags).filter(k => validationFlags[k]);

// Determine safe fallback based on context
const userMessage = (data.user_message || '').toLowerCase();
let fallbackText = '';

// Check what type of failure
const isPhoneLeak = failedRules.includes('phone_number_leak') || failedRules.includes('third_party_message_leak');
const isGenericGreeting = failedRules.includes('generic_greeting_for_action');

if (isPhoneLeak) {
  // Phone leak - generate contextual safe response
  if (userMessage.match(/^(oi|olá|hey|bom dia|boa tarde|boa noite|e aí|fala)/)) {
    fallbackText = 'Oi Márcio! Tudo bem com você? Como posso te ajudar hoje? 😊';
  } else {
    fallbackText = 'Oi Márcio! Estou aqui para te ajudar. Me conta o que precisa! 😊';
  }
} else if (isGenericGreeting) {
  fallbackText = 'Entendi, Márcio! Vou cuidar disso para você. 😊';
} else {
  // Other failures - try to use draft_text if it exists, otherwise generic
  fallbackText = data.draft_text || 'Oi Márcio! Estou aqui para te ajudar. Me conta o que precisa! 😊';
}

return [{
  json: {
    envelope: data.envelope,
    agent_response: data.agent_response,
    qc_result: {
      approved: true,
      final_text: fallbackText,
      issues: failedRules,
      used_fallback: true,
      envelope: data.envelope
    },
    validation_flags: validationFlags
  }
}];

