// TRF_ProcessQCResult - Process QC agent result
const hardValidate = $('TRF_HardValidate').item.json;
const qcOutput = $('Agent_QC').item.json;

let approved = true;
let final_text = hardValidate.draft_text;
let issues = [];

try {
  if (qcOutput.approved !== undefined) {
    approved = qcOutput.approved;
    final_text = qcOutput.final_text || hardValidate.draft_text;
    issues = qcOutput.issues || [];
  } else if (qcOutput.output) {
    let outputText = qcOutput.output;
    outputText = outputText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    const parsed = JSON.parse(outputText);
    approved = parsed.approved !== false;
    final_text = parsed.final_text || hardValidate.draft_text;
    issues = parsed.issues || [];
  }
} catch (e) {
  // Default: approve original
  approved = true;
  final_text = hardValidate.draft_text;
}

// Final safety check on final_text
const leakPatterns = [/```/, /retorne apenas json/i, /contrato de saída/i];
for (const pattern of leakPatterns) {
  if (pattern.test(final_text)) {
    final_text = 'Entendi! Como posso ajudar?';
    issues.push('prompt_leak_in_final');
    break;
  }
}

return [{
  json: {
    envelope: hardValidate.envelope,
    agent_response: hardValidate.agent_response,
    qc_result: {
      approved: approved,
      final_text: final_text,
      issues: issues,
      used_fallback: false
    },
    validation_flags: hardValidate.validation_flags
  }
}];

// TRF_Humanizer - Split final_text into messages[]
const data = $json;
const final_text = data.qc_result.final_text || '';

// Split logic:
// - Short (< 200 chars): 1 message
// - Medium (200-500 chars): 2 messages
// - Long (> 500 chars): 3 messages

const messages = [];

if (final_text.length < 200) {
  // Single message
  messages.push({ message: final_text });
} else if (final_text.length < 500) {
  // Split into 2 messages at sentence boundary
  const sentences = final_text.match(/[^.!?]+[.!?]+/g) || [final_text];
  const midpoint = Math.ceil(sentences.length / 2);

  const part1 = sentences.slice(0, midpoint).join(' ').trim();
  const part2 = sentences.slice(midpoint).join(' ').trim();

  if (part1) messages.push({ message: part1 });
  if (part2) messages.push({ message: part2 });
} else {
  // Split into 3 messages
  const sentences = final_text.match(/[^.!?]+[.!?]+/g) || [final_text];
  const third = Math.ceil(sentences.length / 3);

  const part1 = sentences.slice(0, third).join(' ').trim();
  const part2 = sentences.slice(third, third * 2).join(' ').trim();
  const part3 = sentences.slice(third * 2).join(' ').trim();

  if (part1) messages.push({ message: part1 });
  if (part2) messages.push({ message: part2 });
  if (part3) messages.push({ message: part3 });
}

// Ensure at least 1 message
if (messages.length === 0) {
  messages.push({ message: final_text || 'Entendi!' });
}

return [{
  json: {
    envelope: data.envelope,
    qc_result: data.qc_result,
    validation_flags: data.validation_flags,
    final_response: {
      text: final_text,
      messages: messages,
      agent: data.agent_response?.agent || 'UNKNOWN'
    }
  }
}];
